// --- merged tracks ----------------------------------------------------

/**
 * Merged-track expansion is a rare configuration (you have to explicitly
 * query for one with bracket syntax). We keep a single screenshot here
 * rather than a DOM assertion because the expanded layout has several
 * stacked sub-rows whose coordinates would be tedious to assert.
 */
test.describe('merged tracks', () => {
    test('oncoprint loads and expands a merged track', async ({ page }) => {
        await page.goto(
            '/results/oncoprint?Action=Submit&RPPA_SCORE_THRESHOLD=2.0&Z_SCORE_THRESHOLD=2.0' +
                '&cancer_study_list=coadread_tcga&case_set_id=coadread_tcga_cnaseq' +
                '&data_priority=0&gene_list=%255B%2522RAS%2522%2520KRAS%2520NRAS%2520HRAS%255D' +
                '&geneset_list=%20' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=coadread_tcga_gistic' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=coadread_tcga_mutations&tab_index=tab_visualize'
        );
        await waitForOncoprint(page);

        const track1 = getNthOncoprintTrackOptionsSelectors(1);
        await page.locator(track1.button).hover();
        await page.locator(track1.button).click();
        await page
            .locator(track1.dropdown)
            .waitFor({ state: 'visible', timeout: 10000 });
        await page
            .locator(`${track1.dropdown} li`, { hasText: 'Expand' })
            .click();

        // Give the track time to lay out its expanded children.
        await page.waitForTimeout(4000);
        await waitForOncoprint(page);

        await expectOncoprintScreenshot(page, 'merged-track-expanded.png', {
            extraMasks: ['.oncoprint__controls'],
        });
    });
});

// --- initialization from URL parameters -------------------------------

/**
 * These tests assert *logical* sort order, not pixels — the ACC baseline
 * case should render patients first in a specific order, regardless of
 * data availability changes that would shift visual layout.
 */
test.describe('initialization from URL parameters', () => {
    test('starts in patient mode if URL does not specify show_samples', async ({
        page,
    }) => {
        // Case 1: show_samples not specified -> should default to patient mode.
        await page.goto(
            '/index.do?cancer_study_id=acc_tcga&Z_SCORE_THRESHOLD=2&RPPA_SCORE_THRESHOLD=2' +
                '&data_priority=0&case_set_id=acc_tcga_cnaseq&gene_list=KRAS%2520NRAS%2520BRAF' +
                '&geneset_list=+&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=acc_tcga_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=acc_tcga_gistic'
        );
        await waitForOncoprint(page);
        expect(await getFrontendOncIdOrder(page)).toEqual(ACC_PATIENT_ORDER);

        // Case 2: show_samples=false -> same as default.
        await page.goto(
            '/index.do?cancer_study_id=acc_tcga&Z_SCORE_THRESHOLD=2&RPPA_SCORE_THRESHOLD=2' +
                '&show_samples=false&data_priority=0&case_set_id=acc_tcga_cnaseq' +
                '&gene_list=KRAS%2520NRAS%2520BRAF&geneset_list=+&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=acc_tcga_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=acc_tcga_gistic'
        );
        await waitForOncoprint(page);
        expect(await getFrontendOncIdOrder(page)).toEqual(ACC_PATIENT_ORDER);
    });

    test('starts in sample mode if URL specifies show_samples=true', async ({
        page,
    }) => {
        await page.goto(
            '/index.do?cancer_study_id=acc_tcga&show_samples=true&Z_SCORE_THRESHOLD=2' +
                '&RPPA_SCORE_THRESHOLD=2&data_priority=0&case_set_id=acc_tcga_cnaseq' +
                '&gene_list=KRAS%2520NRAS%2520BRAF&geneset_list=+&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=acc_tcga_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=acc_tcga_gistic'
        );
        await waitForOncoprint(page);
        expect(await getFrontendOncIdOrder(page)).toEqual(ACC_SAMPLE_ORDER);
    });

    /**
     * A bad clinicallist param used to crash the oncoprint entirely.
     * Now it should degrade gracefully — render gene tracks only, still
     * in sample mode, with no clinical track attached.
     */
    test('starts successfully if a specified clinical track does not exist', async ({
        page,
    }) => {
        await page.goto(
            '/index.do?cancer_study_id=acc_tcga&show_samples=true&Z_SCORE_THRESHOLD=2' +
                '&RPPA_SCORE_THRESHOLD=2&data_priority=0&case_set_id=acc_tcga_cnaseq' +
                '&gene_list=KRAS%2520NRAS%2520BRAF&geneset_list=+&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=acc_tcga_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=acc_tcga_gistic' +
                '&clinicallist=asodifjpaosidjfa'
        );
        await waitForOncoprint(page);
        expect(await getFrontendOncIdOrder(page)).toEqual(ACC_SAMPLE_ORDER);
        expect(await getFrontendOncTrackCount(page)).toBe(3); // 3 gene tracks only
    });

    /**
     * Mixed list: real + bogus clinical tracks. Real ones should render,
     * bogus ones should be silently dropped. Sample order stays the same
     * as the plain gene-only case.
     */
    test('starts successfully if some clinical tracks exist and others do not', async ({
        page,
    }) => {
        await page.goto(
            '/index.do?cancer_study_id=acc_tcga&show_samples=true&Z_SCORE_THRESHOLD=2' +
                '&RPPA_SCORE_THRESHOLD=2&data_priority=0&case_set_id=acc_tcga_cnaseq' +
                '&gene_list=KRAS%2520NRAS%2520BRAF&geneset_list=+&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=acc_tcga_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=acc_tcga_gistic' +
                '&clinicallist=CANCER_TYPE,asodifjpaosidjfa,CANCER_TYPE_DETAILED,' +
                'FRACTION_GENOME_ALTERED,aposdijfpoai,MUTATION_COUNT'
        );
        await waitForOncoprint(page);
        // Clinical tracks paint on a slight delay after main tracks.
        await page.waitForTimeout(2000);

        expect(await getFrontendOncIdOrder(page)).toEqual(ACC_SAMPLE_ORDER);
        // 3 genes + 4 valid clinical (CANCER_TYPE, CANCER_TYPE_DETAILED,
        // FRACTION_GENOME_ALTERED, MUTATION_COUNT) = 7
        expect(await getFrontendOncTrackCount(page)).toBe(7);
    });
});

// --- heatmap clustering UI indicator ----------------------------------

/**
 * The cluster/don't-cluster menu items are bolded to reflect the current
 * clustered state. This test toggles the state and asserts the correct
 * menu item is bolded at each step. Pure UI logic — no screenshot.
 */
test.describe('heatmap clustering', () => {
    test('track group options UI reflects clustered state correctly', async ({
        page,
    }) => {
        await page.goto(
            '/results/oncoprint?Z_SCORE_THRESHOLD=2.0&cancer_study_id=coadread_tcga_pub' +
                '&cancer_study_list=coadread_tcga_pub&case_set_id=coadread_tcga_pub_nonhypermut' +
                '&gene_list=KRAS%20NRAS%20BRAF&gene_set_choice=user-defined-list' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=coadread_tcga_pub_gistic' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=coadread_tcga_pub_mutations' +
                '&heatmap_track_groups=coadread_tcga_pub_rna_seq_mrna_median_Zscores%2CKRAS%2CNRAS%2CBRAF' +
                '%3Bcoadread_tcga_pub_methylation_hm27%2CKRAS%2CNRAS%2CBRAF&show_samples=false'
        );
        await waitForOncoprint(page);

        const FONT_WEIGHT_NORMAL = '400';
        const FONT_WEIGHT_BOLD = '700';

        const mrna = getGroupHeaderOptionsSelectors(2);
        const cluster = `${mrna.dropdown} li:nth-child(1)`; // "Cluster"
        const dontCluster = `${mrna.dropdown} li:nth-child(2)`; // "Don't cluster"

        // Helper: open the dropdown and read the CSS font-weight of a given item.
        async function getFontWeight(selector: string): Promise<string> {
            await setDropdownOpen(page, true, mrna.button, mrna.dropdown);
            await page.locator(cluster).waitFor({ state: 'visible' });
            return await page
                .locator(selector)
                .evaluate(el => window.getComputedStyle(el).fontWeight);
        }

        // Initial: unclustered. "Don't cluster" should be bold.
        expect(await getFontWeight(cluster)).toBe(FONT_WEIGHT_NORMAL);
        expect(await getFontWeight(dontCluster)).toBe(FONT_WEIGHT_BOLD);

        // Click Cluster.
        await setDropdownOpen(page, true, mrna.button, mrna.dropdown);
        await page.locator(cluster).click();
        await page.waitForTimeout(500);

        // Now "Cluster" should be bold, "Don't cluster" normal.
        expect(await getFontWeight(cluster)).toBe(FONT_WEIGHT_BOLD);
        expect(await getFontWeight(dontCluster)).toBe(FONT_WEIGHT_NORMAL);

        // Click Don't cluster to toggle back.
        await setDropdownOpen(page, true, mrna.button, mrna.dropdown);
        await page.locator(dontCluster).click();
        await page.waitForTimeout(500);

        // Back to initial: "Don't cluster" bold.
        expect(await getFontWeight(cluster)).toBe(FONT_WEIGHT_NORMAL);
        expect(await getFontWeight(dontCluster)).toBe(FONT_WEIGHT_BOLD);
    });
});

// --- germline mutation --------------------------------------------------

test.describe('germline mutation', () => {
    /**
     * Query BRCA1 on ov_tcga_pub (high germline burden) through the query
     * wizard. The germline-mutated patients should sort to the front of
     * the oncoprint in patient mode, and the per-sample transformation
     * should preserve that ordering.
     */
    test('should sort germline mutation in study ov_tcga_pub', async ({
        page,
    }) => {
        await page.goto('/');
        const search = 'div[data-test=study-search] input[type="text"]';
        await setInputText(
            page,
            search,
            'ovarian serous cystadenocarcinoma tcga nature 2011'
        );
        await waitForNumberOfStudyCheckboxes(page, 1);
        await page.locator('[data-test="StudySelect"] input').click();
        await clickQueryByGeneButton(page);
        await setInputText(page, '[data-test="geneSet"]', 'BRCA1');
        const queryBtn = page.locator('[data-test="queryButton"]');
        await queryBtn.waitFor({ state: 'visible' });
        await queryBtn.click();
        await waitForOncoprint(page);

        expect(await getFrontendOncIdOrder(page)).toEqual(OV_PATIENT_ORDER);

        // Switch to sample mode via the view dropdown.
        await page
            .locator(
                '.oncoprintContainer .oncoprint__controls #viewDropdownButton'
            )
            .click();
        const sampleRadio = page.locator(
            '.oncoprintContainer .oncoprint__controls input[type="radio"][name="columnType"][value="0"]'
        );
        await sampleRadio.waitFor({ state: 'visible' });
        await sampleRadio.click();
        await waitForOncoprint(page);

        expect(await getFrontendOncIdOrder(page)).toEqual(OV_SAMPLE_ORDER);
    });

    /**
     * Toggling "Hide germline" in the global settings should remove
     * germline mutations from the legend and drop the altered-percentage
     * badge on BRCA1 from 12% → 4%. Then toggle it back on and confirm
     * everything returns.
     */
    test('should hide germline mutations correctly', async ({ page }) => {
        await page.goto(
            '/results/oncoprint?Action=Submit&RPPA_SCORE_THRESHOLD=2.0&Z_SCORE_THRESHOLD=2.0' +
                '&cancer_study_list=ov_tcga_pub&case_set_id=ov_tcga_pub_cna_seq' +
                '&data_priority=0&gene_list=BRCA1&geneset_list=%20' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=ov_tcga_pub_gistic' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=ov_tcga_pub_mutations' +
                '&tab_index=tab_visualize'
        );
        await waitForOncoprint(page);

        let legendText = await getTextInOncoprintLegend(page);
        let oncoprintText = await page.locator('#oncoprintDiv').innerText();
        expect(legendText).toContain('Germline Mutation');
        expect(oncoprintText).toContain('12%');

        await setSettingsMenuOpen(page, true);
        const hideGermline = page.locator('input[data-test="HideGermline"]');
        await hideGermline.waitFor({ state: 'visible', timeout: 2000 });
        await hideGermline.click();
        await waitForOncoprint(page);

        legendText = await getTextInOncoprintLegend(page);
        oncoprintText = await page.locator('#oncoprintDiv').innerText();
        expect(legendText).not.toContain('Germline Mutation');
        expect(oncoprintText).toContain('4%');

        // Toggle back on.
        await setSettingsMenuOpen(page, true);
        await hideGermline.waitFor({ state: 'visible', timeout: 2000 });
        await hideGermline.click();
        await waitForOncoprint(page);

        legendText = await getTextInOncoprintLegend(page);
        oncoprintText = await page.locator('#oncoprintDiv').innerText();
        expect(legendText).toContain('Germline Mutation');
        expect(oncoprintText).toContain('12%');
    });

    /**
     * Distinct from "hide germline": "don't color by germline" keeps the
     * mutations counted (percentage stays 12%) but removes the special
     * germline coloring (so the legend no longer shows Germline Mutation).
     */
    test('should not color by germline mutations if that setting is chosen', async ({
        page,
    }) => {
        await page.goto(
            '/results/oncoprint?Action=Submit&RPPA_SCORE_THRESHOLD=2.0&Z_SCORE_THRESHOLD=2.0' +
                '&cancer_study_list=ov_tcga_pub&case_set_id=ov_tcga_pub_cna_seq' +
                '&data_priority=0&gene_list=BRCA1&geneset_list=%20' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=ov_tcga_pub_gistic' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=ov_tcga_pub_mutations' +
                '&tab_index=tab_visualize'
        );
        await waitForOncoprint(page);

        let legendText = await getTextInOncoprintLegend(page);
        let oncoprintText = await page.locator('#oncoprintDiv').innerText();
        expect(legendText).toContain('Germline Mutation');
        expect(oncoprintText).toContain('12%');

        await setOncoprintMutationsMenuOpen(page, true);
        const colorByGermline = page.locator(
            'input[data-test="ColorByGermline"]'
        );
        await colorByGermline.waitFor({ state: 'visible', timeout: 2000 });
        await colorByGermline.click();
        await waitForOncoprint(page);

        legendText = await getTextInOncoprintLegend(page);
        oncoprintText = await page.locator('#oncoprintDiv').innerText();
        expect(legendText).not.toContain('Germline Mutation');
        expect(oncoprintText).toContain('12%'); // still altered

        // Toggle back on.
        await setOncoprintMutationsMenuOpen(page, true);
        await colorByGermline.waitFor({ state: 'visible', timeout: 2000 });
        await colorByGermline.click();
        await waitForOncoprint(page);

        legendText = await getTextInOncoprintLegend(page);
        oncoprintText = await page.locator('#oncoprintDiv').innerText();
        expect(legendText).toContain('Germline Mutation');
        expect(oncoprintText).toContain('12%');
    });
});

// --- custom case list sorting -----------------------------------------

/**
 * The user can submit a query with a hand-typed case list and ask the
 * oncoprint to sort by that exact order. This test builds such a query
 * through the wizard, submits, and verifies the id order matches.
 *
 * The test runs the same assertion twice:
 *   1. After the initial query.
 *   2. After modifying the gene list and re-submitting (via the
 *      "Modify Query" flow on the results page).
 *
 * Step 2 is the interesting regression target — the modify-query path
 * has historically lost the custom case order in subtle ways.
 */
test.describe('custom case list sorting', () => {
    test('should sort patients and samples by custom case list order correctly', async ({
        page,
    }) => {
        // Common inner check shared between the initial and re-submit paths.
        async function doCustomCaseOrderCheck(): Promise<void> {
            await waitForOncoprint(page, 100000);

            // Force sample mode first so the sort-by-case-list setting applies.
            await page
                .locator(
                    '.oncoprintContainer .oncoprint__controls #viewDropdownButton'
                )
                .click();
            const patientRadio = page.locator(
                '.oncoprintContainer .oncoprint__controls input[type="radio"][name="columnType"][value="1"]'
            );
            await patientRadio.waitFor({ state: 'visible' });
            await patientRadio.click();
            await waitForOncoprint(page);

            // Open sort dropdown and click "Sorted by case list order".
            await page.locator('#sortDropdown').click();
            const caseListRadio = page.locator(
                '[data-test="oncoprintSortDropdownMenu"] input[data-test="caseList"]'
            );
            await caseListRadio.waitFor({ state: 'visible' });
            await caseListRadio.click();
            await page.waitForTimeout(200); // allow to sort

            expect(await getFrontendOncIdOrder(page)).toEqual(
                CUSTOM_CASE_PATIENT_ORDER
            );

            // Switch to sample mode.
            await page
                .locator(
                    '.oncoprintContainer .oncoprint__controls #viewDropdownButton'
                )
                .click();
            const sampleRadio = page.locator(
                '.oncoprintContainer .oncoprint__controls input[type="radio"][name="columnType"][value="0"]'
            );
            await sampleRadio.waitFor({ state: 'visible' });
            await sampleRadio.click();
            await waitForOncoprint(page);

            expect(await getFrontendOncIdOrder(page)).toEqual(
                CUSTOM_CASE_SAMPLE_ORDER
            );
        }

        // Build the query: two studies, custom case list, gene panel.
        await page.goto('/');
        const search = 'div[data-test=study-search] input[type="text"]';
        await setInputText(page, search, 'colorectal tcga nature');
        await waitForNumberOfStudyCheckboxes(page, 1);
        await page.locator('[data-test="StudySelect"] input').click();

        await setInputText(
            page,
            search,
            'adrenocortical carcinoma tcga firehose legacy'
        );
        await waitForNumberOfStudyCheckboxes(page, 1);
        // Small settle — the second study's checkbox materializes after
        // the previous selection propagates through state.
        await page.waitForTimeout(1000);
        await page.locator('[data-test="StudySelect"] input').click();

        await clickQueryByGeneButton(page);

        // Wait for molecular profile selector to appear.
        await page
            .locator('[data-test="molecularProfileSelector"]')
            .waitFor({ state: 'visible', timeout: 20000 });

        // Select custom case list option.
        const caseSelectInput = page.locator(
            '[data-test="CaseSetSelector"] .Select-input input'
        );
        await caseSelectInput.fill('User-defined Case List');
        await page
            .locator('[data-test="CaseSetSelector"] .Select-option')
            .click();

        // Enter the custom case list payload.
        await page
            .locator('[data-test="CustomCaseSetInput"]')
            .fill(
                'coadread_tcga_pub:TCGA-AA-3971-01\n' +
                    'acc_tcga:TCGA-OR-A5JC-01\n' +
                    'acc_tcga:TCGA-OR-A5J2-01\n' +
                    'coadread_tcga_pub:TCGA-AA-A00Q-01\n' +
                    'coadread_tcga_pub:TCGA-CM-4748-01\n' +
                    'acc_tcga:TCGA-OR-A5JD-01\n' +
                    'acc_tcga:TCGA-OR-A5J3-01'
            );

        await setInputText(
            page,
            '[data-test="geneSet"]',
            'DKK2 KRAS BCL2L1 RASA1 HLA-B RRAGC'
        );
        const queryButton = page.locator('[data-test="queryButton"]');
        await expect(queryButton).not.toHaveClass(/disabled/);
        await queryButton.click();

        await doCustomCaseOrderCheck();

        // Now modify the gene list via the "Modify Query" button on the
        // results page and re-submit.
        await page.locator('button#modifyQueryBtn').click();
        await page
            .locator('textarea[data-test="geneSet"]')
            .waitFor({ state: 'visible', timeout: 10000 });
        await setInputText(page, 'textarea[data-test="geneSet"]', 'TP53');
        await page.waitForTimeout(200);
        await expect(queryButton).not.toHaveClass(/disabled/);
        await queryButton.click();
        await page.waitForTimeout(200);

        // Get back to the oncoprint tab.
        await page.locator('a.tabAnchor_oncoprint').click();

        await doCustomCaseOrderCheck();
    });
});

// --- clinical legends for altered cases --------------------------------

/**
 * The "only show clinical legends for altered cases" checkbox trims the
 * clinical legend to the values present in altered samples/patients only.
 * These tests toggle that checkbox and assert legend text updates.
 */
test.describe('only show clinical legends for altered cases', () => {
    const altFilterCheckbox =
        '.oncoprintContainer .oncoprint__controls input[type="checkbox"][data-test="onlyShowClinicalLegendsForAltered"]';
    const sampleRadio =
        '.oncoprintContainer .oncoprint__controls input[type="radio"][name="columnType"][value="0"]';
    const viewDropdown =
        '.oncoprintContainer .oncoprint__controls #viewDropdownButton';

    /**
     * With 2 patients (one male BRAF-altered, one female unaltered) and
     * the SEX clinical track, toggling on the filter should hide "Female"
     * from the legend. Flip back off and both should reappear.
     */
    test('only shows legend items for cases which are altered', async ({
        page,
    }) => {
        await page.goto(
            '/index.do?cancer_study_id=coadread_tcga_pub&Z_SCORE_THRESHOLD=2&RPPA_SCORE_THRESHOLD=2' +
                '&data_priority=0&case_set_id=-1' +
                '&case_ids=coadread_tcga_pub%3ATCGA-AA-A00D-01%2Bcoadread_tcga_pub%3ATCGA-A6-2677-01' +
                '&gene_list=BRAF&geneset_list=%20&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=coadread_tcga_pub_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=coadread_tcga_pub_gistic' +
                '&show_samples=false&clinicallist=SEX'
        );
        await waitForOncoprint(page);

        let legend = await getTextInOncoprintLegend(page);
        expect(legend).toContain('Male');
        expect(legend).toContain('Female');

        await page.locator(viewDropdown).click();
        await page.locator(altFilterCheckbox).waitFor({ state: 'visible' });
        await page.locator(altFilterCheckbox).click();
        await waitForOncoprint(page);

        legend = await getTextInOncoprintLegend(page);
        expect(legend).toContain('Male');
        expect(legend).not.toContain('Female');

        // Switch to sample mode — assertion still holds.
        await page.locator(sampleRadio).click();
        await waitForOncoprint(page);

        legend = await getTextInOncoprintLegend(page);
        expect(legend).toContain('Male');
        expect(legend).not.toContain('Female');

        // Toggle the filter back off.
        await page.locator(altFilterCheckbox).click();
        await waitForOncoprint(page);

        legend = await getTextInOncoprintLegend(page);
        expect(legend).toContain('Male');
        expect(legend).toContain('Female');
    });

    /**
     * Edge case: a single unaltered patient. With the filter on, the
     * SEX legend should disappear entirely — nothing left to show.
     */
    test('does not show a legend when no altered cases', async ({ page }) => {
        await page.goto(
            '/index.do?cancer_study_id=coadread_tcga_pub&Z_SCORE_THRESHOLD=2&RPPA_SCORE_THRESHOLD=2' +
                '&data_priority=0&case_set_id=-1' +
                '&case_ids=coadread_tcga_pub%3ATCGA-A6-2677-01' +
                '&gene_list=BRAF&geneset_list=%20&tab_index=tab_visualize&Action=Submit' +
                '&genetic_profile_ids_PROFILE_MUTATION_EXTENDED=coadread_tcga_pub_mutations' +
                '&genetic_profile_ids_PROFILE_COPY_NUMBER_ALTERATION=coadread_tcga_pub_gistic' +
                '&show_samples=false&clinicallist=SEX'
        );
        await waitForOncoprint(page);

        let legend = await getTextInOncoprintLegend(page);
        expect(legend).toContain('Sex');
        expect(legend).toContain('Female');

        await page.locator(viewDropdown).click();
        await page.locator(altFilterCheckbox).waitFor({ state: 'visible' });
        await page.locator(altFilterCheckbox).click();
        await waitForOncoprint(page);

        legend = await getTextInOncoprintLegend(page);
        expect(legend).not.toContain('Sex');
        expect(legend).not.toContain('Female');

        // Sample mode — still nothing.
        await page.locator(sampleRadio).click();
        await waitForOncoprint(page);

        legend = await getTextInOncoprintLegend(page);
        expect(legend).not.toContain('Sex');
        expect(legend).not.toContain('Female');

        // Toggle filter off — Sex legend returns.
        await page.locator(altFilterCheckbox).click();
        await waitForOncoprint(page);

        legend = await getTextInOncoprintLegend(page);
        expect(legend).toContain('Sex');
        expect(legend).toContain('Female');
    });
});
